const input = items[0].json;
const response = input.output || '';

let nutrition = {
  calories: 0,
  protein_g: 0,
  carbs_g: 0,
  fat_g: 0,
  fiber_g: 0,
  sugar_g: 0,
  sodium_mg: 0,
  confidence: 'low',
  notes: 'Could not estimate'
};

try {
  // Remove markdown code blocks if present
  let cleaned = response
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  // Parse the JSON
  nutrition = JSON.parse(cleaned);
} catch (e) {
  console.log('Parse error:', e.message);
  nutrition.notes = 'Parse error: ' + e.message;
}

return { json: nutrition };
